templates.prompt:
"{
  ""template_name"": ""realistic_hands_product_presentation_centered"",
  ""version"": ""2.0 (High Realism Focus)"",
  ""description"": ""A photorealistic studio shot of two hands gently presenting a product bottle in the center of the frame, with large text positioned directly below. Emphasis on realistic skin texture, tangible product details, and natural shadowing."",
  ""brand_input"": {
    ""brand_name"": ""[INSERT BRAND NAME]"",
    ""product_name"": ""[INSERT PRODUCT NAME]"",
    ""brand_colors"": {
      ""background_hex"": ""[INSERT BACKGROUND COLOR HEX - e.g. #dcd0f0]"",
      ""text_hex"": ""#000000"",
      ""accent_hex"": ""#cfff00"",
      ""note"": ""background_hex sets the studio backdrop. accent_hex dictates the nail tip color and the squiggly line below the text.""
    },
    ""hand_specs"": {
      ""skin_tone"": ""[INSERT SKIN TONE - e.g. Medium-dark (identifiable by visible melanin and warm undertones)]"",
      ""nail_style"": ""Manicured, medium-long oval shape with distinct French tips featuring the accent_color.""
    }
  },
  ""technical_specs"": {
    ""resolution"": ""2000x2000px"",
    ""aspect_ratio"": ""1:1"",
    ""file_format"": ""PNG/JPG"",
    ""photographic_style"": ""Macro product photography, high detail, sharp focus.""
  },
  ""visual_assets"": {
    ""instructions"": ""Upload a high-resolution, transparent PNG of your product bottle. The AI will composite it between the hands with realistic lighting and shadows."",
    ""product_integration"": {
      ""type"": ""held_object_composite"",
      ""product_source_image_path"": ""[UPLOAD YOUR PRODUCT BOTTLE IMAGE HERE]"",
      ""position"": ""Centered horizontally, held between both hands."",
      ""scale"": ""Realistic relative to human hands (approx. 4-5 inches tall based on reference)."",
      ""realism_prompt"": ""The uploaded product must appear tangible. The label texture (paper/matte/gloss) must be discernible. The bottle material (plastic/glass) must show realistic specular reflections from the studio lights. It must cast a soft, grounded shadow onto the palm of the lower hand.""
    }
  },
  ""scene_composition"": {
    ""subject_hands"": {
      ""pose"": ""Two hands in a gentle presentation gesture emergeing from left side. The lower hand is cupped facing up, supporting the base of the product. The upper hand (thumb and forefinger visible) gently steadies the top cap."",
      ""realism_prompt"": ""Highly photorealistic macro photograph of human hands. Focus on high-detail skin texture, including natural pores, fine lines, knuckles, and cuticles. The skin must have subsurface scattering to look alive, not waxy or synthetic. No smoothing filters."",
      ""attributes"": {
        ""tone"": ""Defined by hand_specs.skin_tone"",
        ""nails"": ""Defined by hand_specs.nail_style and brand_colors.accent_hex""
      }
    },
    ""environment"": {
      ""setting"": ""Professional photo studio seamless backdrop."",
      ""background_color"": ""Solid color defined by brand_colors.background_hex."",
      ""lighting"": ""Soft, diffused professional studio lighting. Key light from the top-front to create gentle highlights on the fingernails and the shoulder of the product bottle, and to cast soft, realistic shadows within the hands.""
    }
  },
"text_content": {
  "position": "Centered horizontally, positioned directly below the lower hand.",
  "design_philosophy": "Typography is a visual design object — not plain text. Letters have weight, texture, and spatial presence. This is editorial luxury design.",
  "main_headline": {
    "text": "[INSERT CAPTION]",
    "font_style": "High-contrast editorial serif — think Didot, Bodoni, or ABC Arizona. Extreme stroke contrast between hairlines and swells. Letterforms should feel sculptural.",
    "weight_play": "Split the headline: first word or two in ultra-bold black weight, remainder in elegant thin/light weight — or vice versa. The contrast IS the design.",
    "tracking": "Wide, airy letter-spacing — luxury breathing room between characters. Minimum 0.15em tracking.",
    "color": "Defined by brand_colors.text_hex",
    "size": "Large, dominant — nearly full canvas width. Text bleeds edge-to-edge if needed.",
    "special_treatment": "Consider: one oversized drop cap, a word rendered in italic counterpoint, or alternate glyphs/swash characters for a letter like 'S', 'W', or 'Q'."
  },
  "brand_name_sub": {
    "text": "[BRAND NAME or PRODUCT NAME]",
    "font_style": "Condensed grotesque or geometric sans-serif — extreme contrast with the serif headline. All caps, tight tracking.",
    "size": "Small, whisper-thin — subservient to headline but crisp and precise.",
    "color": "Defined by brand_colors.text_hex at 60% opacity or accent_hex"
  },
  "accent_element": {
    "type": "Hand-drawn squiggly underline OR a fine rule line with gestural energy",
    "position": "Centered directly below the main headline.",
    "color": "Defined by brand_colors.accent_hex",
    "style": "Organic, slightly imperfect — like a brushstroke or ink flourish. Not a straight line. Adds life and craft feeling."
  },
  "layout_feel": "Think Vogue editorial spread or Aesop campaign — where the type layout itself is worth photographing."
}
    ""accent_element"": {
      ""type"": ""Squiggly line graphic"",
      ""position"": ""Centered directly below the main headline text."",
      ""color"": ""Defined by brand_colors.accent_hex"",
      ""style"": ""Hand-drawn wavy line look.""
    }
  },
  ""layout_instructions"": {
    ""composition_rule"": ""Central Symmetry. The hands and product form the central focal mass. The text block is center-aligned beneath it. Both hands comes from same side, left-side."",
    ""spacing"": ""Generous padding at the top. The hands occupy the vertical center. Clear separation between the bottom of the hands and the top of the text block.""
  }
}"

{
  "template_info": {
    "name": "Floating Product with Specification Footer (Empty Template)",
    "version": "2.0",
    "base_resolution": "2000x2000px",
    "aspect_ratio": "1:1",
    "description": "A split-background design featuring a floating 3D product on the right, bold benefit text on the left, and a 3-column footer. Ready for custom input."
  },
  "user_configuration": {
    "product": {
      "image_source": "[UPLOAD_IMAGE_FILE_HERE (e.g., product_transparent.png)]",
      "render_style": "[INSERT_STYLE_PROMPT (e.g., 3D realistic, natural studio lighting, ambient occlusion, floating perspective)]",
      "shadow_type": "[INSERT_SHADOW_STYLE (e.g., realistic soft diffused drop shadow and contact shadow)]"
    },
    "color_palette": {
      "background_primary_top": "[INSERT_HEX_CODE (e.g., #4A2C6D - Main Dark Background)]",
      "background_secondary_bottom": "[INSERT_HEX_CODE (e.g., #D5C2E8 - Footer Light Background)]",
      "accent_badge": "[INSERT_HEX_CODE (e.g., #60A533 - Circular Badge Color)]",
      "text_main_light": "[INSERT_HEX_CODE (e.g., #FFFFFF - Headline Text)]",
      "text_secondary_dark": "[INSERT_HEX_CODE (e.g., #4A2C6D - Footer Text)]"
    },
    "text_content": {
      "badge_text": "[INSERT_BADGE_TEXT (e.g., New\nArrival)]",
      "headline_text": "[INSERT_HEADLINE (e.g., Brand Name\nProduct)]",
      "subheadline_text": "[INSERT_SUBHEADLINE (e.g., Key Benefit or Tagline)]",
      "footer_col_1": {
        "value": "[INSERT_VALUE (e.g., 60)]",
        "label": "[INSERT_LABEL (e.g., Count)]"
      },
      "footer_col_2": {
        "value": "[INSERT_VALUE (e.g., Ages 2+)]",
        "label": "[INSERT_LABEL (e.g., Years)]"
      },
      "footer_col_3": {
        "value": "[INSERT_VALUE (e.g., Vitamin C)]",
        "label": "[INSERT_LABEL (e.g., Ingredient)]"
      }
    },
    "typography": {
      "font_family_primary": "[INSERT_FONT_NAME (e.g., Montserrat, Poppins, Roboto)]",
      "font_size_scale": {
        "badge": "small",
        "headline": "medium",
        "subheadline": "small",
        "footer_value": "extra-small",
        "footer_label": "extra-small"
      }
    }
  },
  "layout_blueprint": {
    "canvas": {
      "width": 2000,
      "height": 2000,
      "background_color": "RGB(255,255,255)"
    },
    "sections": [
      {
        "id": "upper_background",
        "type": "container",
        "area": "top_75_percent",
        "fill": "{user_configuration.color_palette.background_primary_top}",
        "elements": [
          {
            "id": "feature_badge",
            "type": "shape_circle",
            "position": {
              "x": "10%",
              "y": "18%"
            },
            "size": "5%",
            "fill": "{user_configuration.color_palette.accent_badge}",
            "content": {
              "text": "{user_configuration.text_content.badge_text}",
              "color": "{user_configuration.color_palette.text_main_light}",
              "align": "center",
              "font_size": "{user_configuration.typography.font_size_scale.badge}",
              "weight": "bold"
            }
          },
          {
            "id": "main_copy",
            "type": "text_block",
            "position": {
              "x": "10%",
              "y": "50%"
            },
            "width": "40%",
            "content": [
              {
                "text": "{user_configuration.text_content.headline_text}",
                "color": "{user_configuration.color_palette.text_main_light}",
                "font_size": "{user_configuration.typography.font_size_scale.headline}",
                "weight": "extrabold",
                "line_height": "1.1",
                "align": "left"
              },
              {
                "text": "{user_configuration.text_content.subheadline_text}",
                "color": "{user_configuration.color_palette.text_main_light}",
                "font_size": "{user_configuration.typography.font_size_scale.subheadline}",
                "weight": "medium",
                "margin_top": "20px",
                "align": "left"
              }
            ]
          },
          {
            "id": "product_hero",
            "type": "image_container",
            "position": {
              "x": "70%",
              "y": "45%"
            },
            "width": "40%",
            "anchor": "center",
            "source": "{user_configuration.product.image_source}",
            "effects": [
              "floating_illusion",
              "{user_configuration.product.shadow_type}"
            ]
          }
        ]
      },
      {
        "id": "lower_footer",
        "type": "container",
        "area": "bottom_25_percent",
        "fill": "{user_configuration.color_palette.background_secondary_bottom}",
        "layout": "grid_3_columns",
        "divider_style": "vertical_line_center",
        "content_style": {
          "color": "{user_configuration.color_palette.text_secondary_dark}",
          "align": "center",
          "weight": "bold"
        },
        "columns": [
          {
            "value": "{user_configuration.text_content.footer_col_1.value}",
            "label": "{user_configuration.text_content.footer_col_1.label}",
            "value_size": "{user_configuration.typography.font_size_scale.footer_value}",
            "label_size": "{user_configuration.typography.font_size_scale.footer_label}"
          },
          {
            "value": "{user_configuration.text_content.footer_col_2.value}",
            "label": "{user_configuration.text_content.footer_col_2.label}",
            "value_size": "{user_configuration.typography.font_size_scale.footer_value}",
            "label_size": "{user_configuration.typography.font_size_scale.footer_label}"
          },
          {
            "value": "{user_configuration.text_content.footer_col_3.value}",
            "label": "{user_configuration.text_content.footer_col_3.label}",
            "value_size": "{user_configuration.typography.font_size_scale.footer_value}",
            "label_size": "{user_configuration.typography.font_size_scale.footer_label}"
          }
        ]
      }
    ]
  }
}

{
  "template_meta": {
    "name": "Shopify_Duo_Showcase_Reference_V1",
    "target_platform": "Shopify",
    "version": "1.2_Template"
  },
  "canvas_settings": {
    "width": 2000,
    "height": 2000,
    "units": "px",
    "aspect_ratio": "1:1",
    "background_mode": "adaptive_monochromatic"
  },
  "user_inputs": {
    "reference_image_url": "uploaded product image",
    "brand_text": "[BRAND_NAME]",
    "product_name": "[PRODUCT_NAME]",
    "product_descriptor": "premium product descriptor",
    "volume_text": "product specs",
    "brand_color_hex": "[BG_COLOR]"
  },
  "layout_structure": {
    "composition_type": "studio_product_duo",
    "placement_rules": {
      "left_anchor": {
        "element": "primary_vessel",
        "description": "Unboxed product container",
        "position_x": "30%",
        "position_y": "50%",
        "rotation": "0 degrees",
        "scale": "1.0"
      },
      "right_anchor": {
        "element": "retail_packaging",
        "description": "Outer product box",
        "position_x": "70%",
        "position_y": "50%",
        "rotation": "15 degrees_y-axis_perspective",
        "scale": "1.1"
      }
    },
    "surface_interaction": "hard_shadows_bottom_left_to_right"
  },
  "text_hierarchy_map": {
    "brand_logo": {
      "content": "[BRAND_NAME]",
      "placement_on_product": "center_body",
      "font_size_class": "large",
      "style": "bold_serif",
      "color": "[TEXT_COLOR]"
    },
    "product_title": {
      "content": "[PRODUCT_NAME]",
      "placement_on_product": "lower_third_center",
      "font_size_class": "medium",
      "style": "bold_serif",
      "color": "[TEXT_COLOR]"
    },
    "descriptor": {
      "content": "premium product descriptor",
      "placement_on_product": "below_title",
      "font_size_class": "small",
      "style": "regular_serif",
      "color": "[TEXT_COLOR]"
    },
    "specs": {
      "content": "product specs",
      "placement_on_product": "bottom_edge_center",
      "font_size_class": "extra_small",
      "style": "light_serif",
      "color": "[TEXT_COLOR]"
    }
  },
  "generative_prompt_construction": {
    "instruction": "Create a high-key product photography studio shot.",
    "subject_definition": "Extract subject from the uploaded product image. Separate into two distinct objects: 1. The product container (jar, tube, or vessel) on the LEFT. 2. The product outer packaging box on the RIGHT.",
    "environment": "Place objects on a seamless surface. Background color must be a tone matching [BG_COLOR].",
    "lighting": "Soft studio lighting with a directional key light from the top-left, casting distinct, sharp shadows to the right.",
    "text_rendering_instruction": "Apply '[BRAND_NAME]' and '[PRODUCT_NAME]' using a bold serif font on the product labels only. Text color: [TEXT_COLOR].",
    "final_output_specs": "Photorealistic, 8k resolution, commercial advertising style."
  }
}

{
  "template_meta": {
    "template_name": "3-Column_Product_Center_Ecommerce_Image_TopView",
    "base_resolution": "2000x2000px",
    "aspect_ratio": "1:1",
    "color_space": "RGB",
    "description": "A template where the main product image is placed in the center card with a top-down diagonal view, flanked by two generated cards showing product contents/accessories."
  },
  "global_settings": {
    "background_color_hex": "#F5F5F5",
    "primary_text_color_hex": "#000000",
    "accent_color_hex": "#000000",
    "font_family_style": "Sans-Serif, Geometric, Bold",
    "layout_style": "Symmetrical, Grid-based, Minimalist, Borderless"
  },
  "user_input_variables": {
    "brand_color": "#000000",
    "background_choice": "RGB(245,245,245)",
    "product_type": "[INSERT PRODUCT TYPE HERE]",
    "main_product_image_ref": "[UPLOAD_YOUR_MAIN_PRODUCT.jpg]",
    "main_headline_text": "[INSERT MAIN HEADLINE HERE]",
    "sub_headline_text": "[INSERT Sub-headline or Benefit Statement Here]",
    "feature_1": {
      "label_text": "[INSERT Feature 1 Label]",
      "image_subject": "[INSERT the description of the left card image. Example: A close-up of the product ingredients on a clean surface]"
    },
    "feature_2": {
      "label_text": "[INSERT Feature 2 Label]",
      "image_subject": "The main product {main_product_image_ref} viewed from a top-down angle, placed diagonally across the frame on [INSERT background surface description]"
    },
    "feature_3": {
      "label_text": "[INSERT Feature 3 Label]",
      "image_subject": "[INSERT the description of the right card image. Example: The product being used in a lifestyle setting]"
    }
  },
  "layout_structure": {
    "header_section": {
      "position": "top_center",
      "padding_top": "medium_spacing",
      "elements": [
        {
          "type": "text",
          "id": "headline",
          "content": "{main_headline_text}",
          "font_size": "large",
          "font_weight": "800",
          "color": "{primary_text_color_hex}",
          "alignment": "center"
        },
        {
          "type": "text",
          "id": "sub_headline",
          "content": "{sub_headline_text}",
          "font_size": "medium-large",
          "font_weight": "600",
          "color": "{primary_text_color_hex}",
          "alignment": "center",
          "margin_top": "small_spacing"
        }
      ]
    },
    "feature_grid_section": {
      "position": "bottom_center",
      "layout_type": "horizontal_flex_row",
      "gap": "balanced_spacing",
      "padding_bottom": "medium_spacing",
      "card_style": {
        "width": "equal_thirds_relative",
        "height": "vertical_tall_aspect",
        "shape_profile": "rounded_rectangle",
        "border_radius": "soft_rounded",
        "border_stroke": "none",
        "mask_shape": "rounded_rectangle"
      },
      "cards": [
        {
          "slot": "1",
          "header_bg_color": "{brand_color}",
          "header_text_color": "#FFFFFF",
          "header_text": "{feature_1.label_text}",
          "header_font_size": "medium",
          "image_source": "generative_subject",
          "image_content": "{feature_1.image_subject}"
        },
        {
          "slot": "2",
          "header_bg_color": "{brand_color}",
          "header_text_color": "#FFFFFF",
          "header_text": "{feature_2.label_text}",
          "header_font_size": "medium",
          "image_source": "direct_product_reference",
          "image_content": "{main_product_image_ref}"
        },
        {
          "slot": "3",
          "header_bg_color": "{brand_color}",
          "header_text_color": "#FFFFFF",
          "header_text": "{feature_3.label_text}",
          "header_font_size": "medium",
          "image_source": "generative_subject",
          "image_content": "{feature_3.image_subject}"
        }
      ]
    }
  },
  "generative_image_prompt": "A professional high-resolution Ecommerce product listing image, 2000x2000px on a clean {background_choice} background. Top center features bold text '{main_headline_text}' in {brand_color}, followed by a subtitle '{sub_headline_text}'. Below are three vertical, borderless rounded rectangular panels arranged side-by-side. Each panel contains a realistic background environment (e.g., kitchen counter, wooden surface, or nature scene) rather than a solid color. 1) The Left Panel ('{feature_1.label_text}') displays {feature_1.image_subject}. 2) The Middle Panel ('{feature_2.label_text}') displays the exact user-provided product image ({main_product_image_ref}) composited realistically into the environment, viewed specifically from a straight top-down angle and positioned diagonally across the frame. 3) The Right Panel ('{feature_3.label_text}') displays {feature_3.image_subject}. The lighting and environment style must be consistent across all three panels."
}

