  "user_variables": {
    "assets": {
      "product_image_path": "[UPLOAD/INSERT FILE NAME, e.g., product.jpg]"
    },
    "product_name": "[INSERT PRODUCT NAME]",
    "product_description": "[INSERT SHORT DESCRIPTION]",
    "sample_image_style": "[INSERT STYLE GUIDE, e.g., Realistic lifestyle photography, studio lighting]"
  },
  "layout_structure": {
    "header": {
      "text_content": "[INSERT MAIN HEADLINE HERE\nUSE \\n FOR NEW LINE]",
      "position": "top_center",
      "font_size_category": "very_large",
      "font_weight": "bold",
      "alignment": "center",
      "color_ref": "primary_text_color"
    },
    "grid_container": {
      "type": "grid",
      "rows": 2,
      "columns": 2,
      "gap": "medium"
    },
    "panels": [
      {
        "id": "panel_1",
        "position": "row_1_left",
        "shape": "square_rounded",
        "corner_radius": "40px",
        "background_ref": "panel_background_color",
        "text_overlay": {
          "content": "[INSERT FEATURE 1 TITLE]",
          "position": "top_left",
          "padding": "30px",
          "font_size_category": "medium",
          "font_weight": "bold",
          "color_ref": "secondary_text_color"
        },
        "image_prompt": "[INSERT DESCRIPTION OF IMAGE 1: e.g., Close-up of hands using {product_name} from {product_image_path} to demonstrate Feature 1]"
      },
      {
        "id": "panel_2",
        "position": "row_1_right",
        "shape": "square_rounded",
        "corner_radius": "40px",
        "background_ref": "panel_background_color",
        "text_overlay": {
          "content": "[INSERT FEATURE 2 TITLE]",
          "position": "bottom_center",
          "padding": "30px",
          "font_size_category": "medium",
          "font_weight": "bold",
          "color_ref": "secondary_text_color"
        },
        "image_prompt": "[INSERT DESCRIPTION OF 2: e.g., Top down view of {product_name} from {product_image_path} demonstrating Feature 2]"
      },
      {
        "id": "panel_3",
        "position": "row_2_full_width",
        "shape": "rectangle_rounded",
        "corner_radius": "40px",
        "background_ref": "panel_background_color",
        "text_overlay": {
          "content": "[INSERT FEATURE 3 TITLE\nCAN BE TWO LINES]",
          "position": "center_left",
          "padding": "50px",
