{
  "template_meta": {
    "name": "Dating_App_Product_Profile_Card",
    "version": "1.1",
    "base_resolution": "2000x2000px",
    "aspect_ratio": "1:1",
    "description": "A product presented as a dating app profile card. White app header (logo or store name), gradient card with product overflowing the top edge, product name + inline variant badge, pronoun field, bio field, and 5-button swipe action row. Gradient should echo the product shade or brand colours."
  },
  "user_inputs": {
    "app_name": "[INSERT APP OR STORE NAME \u2014 e.g. Cosmetic Capital]",
    "logo_image": "[UPLOAD LOGO IMAGE \u2014 if available; otherwise render app_name as text]",
    "brand_name": "[INSERT BRAND NAME \u2014 e.g. L'Oreal Paris]",
    "product_name": "[INSERT PRODUCT NAME \u2014 e.g. Bright Reveal SPF15 Cream]",
    "product_variant": "[INSERT VARIANT / SHADE / SIZE \u2014 e.g. 50ml or Tan]",
    "product_image": "[UPLOAD PRODUCT IMAGE \u2014 transparent PNG preferred]",
    "pronoun_label": "[INSERT PRONOUNS \u2014 e.g. She/Her | He/Him | They/Them]",
    "bio_text": "[INSERT BIO \u2014 one sentence written as if the product is introducing itself on a dating app. Witty. Sneak in one product USP or spec.]",
    "card_gradient_top_hex": "[INSERT TOP GRADIENT HEX \u2014 match to product shade or brand primary, e.g. #7A5530]",
    "card_gradient_bottom_hex": "[INSERT BOTTOM GRADIENT HEX \u2014 lighter/warmer version, e.g. #C4A55A]",
