      {
        "icon": "rewind_arrow",
        "color_hex": "#F5A623"
      },
      {
        "icon": "x_cross",
        "color_hex": "#E05252"
      },
      {
        "icon": "star",
        "color_hex": "#4A90D9"
      },
      {
        "icon": "heart",
        "color_hex": "#4ECDC4"
      },
      {
        "icon": "lightning_bolt",
        "color_hex": "#9B59B6"
