              "x": "50%",
              "y": "50%"
            },
            "width": "35%",
            "anchor": "center",
            "rendering": {
              "background": "transparent",
              "style": "extract wordmark onto white \u2014 strip dark background from logo, render brand colours only"
            }
          }
        ]
      },
      {
        "id": "profile_card",
        "type": "container",
        "area": {
          "top": "9%",
          "height": "78%",
          "left": "4%",
          "right": "4%"
        },
        "fill_gradient": {
          "type": "linear",
          "direction": "top_to_bottom",
          "color_start": "{user_inputs.card_gradient_top_hex}",
          "color_end": "{user_inputs.card_gradient_bottom_hex}"
        },
        "border_radius": "40px",
        "overflow": "visible",
