            "overflow_note": "Product cap/top must clearly extend ABOVE the card boundary into the white header zone \u2014 at least 15-20% of the product height sits above the card top edge.",
            "rendering": {
              "style": "photorealistic studio product shot",
              "background": "transparent",
              "lighting": "soft diffused studio, key light top-right, specular highlight on product shoulder/cap",
