            },
            "width": "86%",
            "elements": [
              {
                "id": "bio_icon",
                "type": "icon",
                "icon_name": "magnifying_glass",
                "size": "20px",
                "color": "rgba(255,255,255,0.85)"
              },
              {
                "id": "bio_text",
                "type": "text",
                "content": "{user_inputs.bio_text}",
                "font_family": "Sans-serif",
                "font_size": "x-small",
                "font_weight": "400",
                "color": "rgba(255,255,255,0.85)",
                "line_height": "1.4",
                "margin_left": "6px",
                "size_note": "bio text must be visibly smaller than product name \u2014 approximately 27-30% of headline font size"
              }
            ]
          }
        ]
      },
      {
        "id": "action_buttons_row",
        "type": "container",
        "area": {
          "top": "87%",
          "height": "13%",
          "left": "0%",
          "right": "0%"
        },
        "fill": "#F2F2F2",
        "layout": "horizontal_center",
        "gap": "4%",
        "vertical_alignment": "middle",
        "elements": [
          {
            "id": "btn_rewind",
